def abs_val(n):
    if n < 0:
        return -n
    return n

n = int(input())
print(abs_val(n))

def is_prime(n):
    if n < 2:
        return False
    for d in range(2, n):
        if n % d == 0:
            return False
    return True

n = int(input())
print('PRIME' if is_prime(n) else 'NOT')

